import { useEffect, useState } from "react";
import API from "../api";

export default function Dashboard() {
	const [data, setData] = useState([]);
	const [editSeat, setEditSeat] = useState(null);
	const [form, setForm] = useState({ name: "", age: "", gender: "" });

	const fetchData = async () => {
		const res = await API.get("/tickets/closed/all");
		setData(res.data);
	};

	useEffect(() => {
		fetchData();
	}, []);

	const startEdit = (seat) => {
		setEditSeat(seat.seatNumber);
		setForm(seat.user);
	};

	const saveEdit = async () => {
		await API.put(`/tickets/${editSeat}`, form);
		setEditSeat(null);
		fetchData();
	};

	const deleteSeat = async (seat) => {
		await API.delete(`/tickets/${seat}`);
		fetchData();
	};

	return (
		<div>
			<h2>Dashboard</h2>

			<table border="1">
				<thead>
					<tr>
						<th>Name</th>
						<th>Age</th>
						<th>Gender</th>
						<th>Seat</th>
						<th>Action</th>
					</tr>
				</thead>

				<tbody>
					{data.map((d) => (
						<tr key={d.seatNumber}>
							<td>
								{editSeat === d.seatNumber ? (
									<input
										value={form.name}
										onChange={(e) => setForm({ ...form, name: e.target.value })}
									/>
								) : (
									d.user?.name || "-"
								)}
							</td>

							<td>
								{editSeat === d.seatNumber ? (
									<input
										value={form.age}
										onChange={(e) => setForm({ ...form, age: e.target.value })}
									/>
								) : (
									d.user?.age || "-"
								)}
							</td>

							<td>
								{editSeat === d.seatNumber ? (
									<input
										value={form.gender}
										onChange={(e) =>
											setForm({ ...form, gender: e.target.value })
										}
									/>
								) : (
									d.user?.gender || "-"
								)}
							</td>

							<td>{d.seatNumber}</td>

							<td>
								{editSeat === d.seatNumber ? (
									<button onClick={saveEdit}>Save</button>
								) : (
									<button onClick={() => startEdit(d)}>Edit</button>
								)}
								<button onClick={() => deleteSeat(d.seatNumber)}>Delete</button>
							</td>
						</tr>
					))}
				</tbody>
			</table>
		</div>
	);
}
